using DataAccessLayer.Entity; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace DataAccessLayer.Configurations;
public class BranchStaffMembershipConfiguration : IEntityTypeConfiguration<BranchStaffMembership> { public void Configure(EntityTypeBuilder<BranchStaffMembership> b) { b.HasKey(x=>x.BranchStaffMembershipID); b.HasIndex(x=>new{x.BranchID,x.UserID,x.EffectiveFrom}).IsUnique(); b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchID).OnDelete(DeleteBehavior.Restrict); b.HasOne(x=>x.User).WithMany().HasForeignKey(x=>x.UserID).OnDelete(DeleteBehavior.Restrict); b.ToTable(t=>t.HasCheckConstraint("CK_BranchStaffMembership_Dates", "\"EffectiveTo\" IS NULL OR \"EffectiveTo\" >= \"EffectiveFrom\"")); } }
public class BranchManagerMembershipConfiguration : IEntityTypeConfiguration<BranchManagerMembership> { public void Configure(EntityTypeBuilder<BranchManagerMembership> b) { b.HasKey(x=>x.BranchManagerMembershipID); b.HasIndex(x=>new{x.BranchID,x.UserID}).IsUnique(); b.HasIndex(x=>x.UserID).IsUnique().HasFilter("\"IsActive\" = TRUE"); b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchID).OnDelete(DeleteBehavior.Restrict); b.HasOne(x=>x.User).WithMany().HasForeignKey(x=>x.UserID).OnDelete(DeleteBehavior.Restrict); } }
public class BranchWorkScheduleConfiguration : IEntityTypeConfiguration<BranchWorkSchedule> { public void Configure(EntityTypeBuilder<BranchWorkSchedule> b) { b.HasKey(x=>x.BranchWorkScheduleID); b.HasIndex(x=>x.BranchID).IsUnique(); b.Property(x=>x.TimezoneId).HasMaxLength(100); b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchID).OnDelete(DeleteBehavior.Cascade); b.ToTable(t=>t.HasCheckConstraint("CK_BranchWorkSchedule_Times", "\"EndLocalTime\" > \"StartLocalTime\" AND \"CheckoutGraceMinutes\" >= 0")); } }
